#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=30,Mod=1e9+7;
int a[N][N],g[65540],f[65540],II,ans,pos[N];
inline void print(int k){if(k>1)print(k>>1);putchar((k&1)+'0');}
inline void dfs(int i,int p,int cur=1)
{
	if(cur>p){print(i);puts("");
	if(i^II&&i)ans=(ans+1ll*f[i]*g[II^i]%Mod)%Mod;}
	else dfs(i,p,cur+1),dfs(i^pos[cur],p,cur+1);return;
}
int main()
{
	int n=read(),len=(1<<n)-1;rep(1,n,i)rep(1,n,j)a[i][j]=read();
	g[0]=1;rep(1,len,i)
	{
		rep(0,n-1,j)if((1<<j)&i)
		{
			int tmp=(1<<j)^i;g[i]=g[tmp];
			rep(j,n-1,k)if((1<<k)&tmp){g[i]=1ll*g[i]*(a[j+1][k+1]+1)%Mod;} break;
		}
	}
//	rep(0,len,i)print(i),printf(": %d\n",g[i]);
	memcpy(f,g,sizeof(g));
//	/printf("%d\n",f[len]);
//	rep(1,len,i)
//	{
//		int p=0;II=i;ans=0;
//		rep(0,n-1,j)if((1<<j)&i)pos[++p]=(1<<j);
//		dfs(i,p);printf("ggg");print(i);printf(": %d\n",ans);
//		f[i]=((f[i]-ans)%Mod+Mod)%Mod;
//	}
	rep(1,len,i)
	{
		f[i]=g[i];int cur=i^(i&-i);
		for(int j=cur;j;j=(j-1)&cur)
		{
//			print(i);puts("");
			f[i]=(f[i]-1ll*g[j]*f[i^j]%Mod+Mod)%Mod;
		}
//		putchar('g');print(k);puts("");	
	}
	printf("%d\n",f[len]);return 0;
}
